class MinHeap {
  private heap: ListNode[] = [];

  get size(): number {
    return this.heap.length;
  }

  push(node: ListNode): void {
    this.heap.push(node);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): ListNode {
    const top = this.heap[0];
    const last = this.heap.pop()!;
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.bubbleDown(0);
    }
    return top;
  }

  private bubbleUp(i: number): void {
    while (i > 0) {
      const parent = (i - 1) >> 1;
      if (this.heap[parent].val <= this.heap[i].val) break;
      [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
      i = parent;
    }
  }

  private bubbleDown(i: number): void {
    const n = this.heap.length;
    while (true) {
      let smallest = i;
      const left = 2 * i + 1;
      const right = 2 * i + 2;
      if (left < n && this.heap[left].val < this.heap[smallest].val) smallest = left;
      if (right < n && this.heap[right].val < this.heap[smallest].val) smallest = right;
      if (smallest === i) break;
      [this.heap[smallest], this.heap[i]] = [this.heap[i], this.heap[smallest]];
      i = smallest;
    }
  }
}

function mergeKLists(lists: (ListNode | null)[]): ListNode | null {
  const heap = new MinHeap();
  for (const node of lists) {
    if (node !== null) heap.push(node);
  }

  const dummy = new ListNode(0);
  let current = dummy;

  while (heap.size > 0) {
    const node = heap.pop();
    current.next = node;
    current = node;
    if (node.next !== null) heap.push(node.next);
  }

  current.next = null;
  return dummy.next;
}

