function findWords(board: string[][], words: string[]): string[] {
  // 1. build a trie from all words so shared prefixes are explored only once
  // 2. for each cell in the board, run DFS/backtracking following trie edges
  //    (only descend into a neighbor if trie has an edge for that character)
  // 3. when a trie node has `word` set, record it and clear it to avoid duplicates
  // 4. mark cells visited during the current path (e.g. temporarily overwrite
  //    the cell) and restore them on backtrack
