solution:
function solveNQueens(n: number): string[][] {
  const results: string[][] = [];
  const cols = new Set<number>();
  const diag1 = new Set<number>(); // row - col
  const diag2 = new Set<number>(); // row + col
  const queenCol: number[] = new Array(n).fill(-1); // queenCol[row] = column

  function buildBoard(): string[] {
    const board: string[] = [];
    for (let row = 0; row < n; row++) {
      const rowChars = new Array(n).fill('.');
      rowChars[queenCol[row]] = 'Q';
      board.push(rowChars.join(''));
    }
    return board;
  }

  function backtrack(row: number): void {
    if (row === n) {
      results.push(buildBoard());
      return;
    }

    for (let col = 0; col < n; col++) {
      const d1 = row - col;
      const d2 = row + col;
      if (cols.has(col) || diag1.has(d1) || diag2.has(d2)) continue;

      cols.add(col);
      diag1.add(d1);
      diag2.add(d2);
      queenCol[row] = col;

      backtrack(row + 1);

      cols.delete(col);
      diag1.delete(d1);
      diag2.delete(d2);
      queenCol[row] = -1;
    }
  }

  backtrack(0);
  return results;
}

