  //    keep a `distances` map/array initialized to Infinity except k = 0
  // 3. pop the smallest-distance entry; if it's stale (a better distance
  //    was already recorded), skip it; otherwise relax its neighbors and
  //    push improved distances into the heap
  // 4. once done, if any node still has distance Infinity, return -1;
  //    otherwise return the max distance across all nodes
}

