function alienOrder(words: string[]): string {
  // 1. collect every unique letter across all words (these are the graph nodes)
  // 2. for each pair of adjacent words, find the first position where their
  //    letters differ - that gives one ordering edge (earlier letter -> later letter)
  //    - if no differing position is found and the first word is LONGER than
  //      the second, that's the invalid-prefix case -> return ""
  // 3. topologically sort the resulting graph (Kahn's algorithm: track
  //    in-degrees, repeatedly remove zero-in-degree nodes)
  // 4. if the topological sort doesn't include every letter, there's a cycle -> return ""
}

