function alienOrder(words: string[]): string {
  const adjacency = new Map<string, Set<string>>();
  const inDegree = new Map<string, number>();

  for (const word of words) {
    for (const ch of word) {
      if (!adjacency.has(ch)) {
        adjacency.set(ch, new Set());
        inDegree.set(ch, 0);
      }
    }
  }

  for (let i = 0; i < words.length - 1; i++) {
    const first = words[i];
    const second = words[i + 1];
    const minLen = Math.min(first.length, second.length);

    let foundDifference = false;
    for (let j = 0; j < minLen; j++) {
      if (first[j] !== second[j]) {
        if (!adjacency.get(first[j])!.has(second[j])) {
          adjacency.get(first[j])!.add(second[j]);
          inDegree.set(second[j], inDegree.get(second[j])! + 1);
        }
        foundDifference = true;
        break;
      }
    }

    if (!foundDifference && first.length > second.length) {
      return '';
    }
  }

  const queue: string[] = [];
  for (const [letter, degree] of inDegree) {
    if (degree === 0) queue.push(letter);
  }

  const result: string[] = [];
  while (queue.length > 0) {
    const letter = queue.shift()!;
    result.push(letter);

    for (const neighbor of adjacency.get(letter)!) {
      inDegree.set(neighbor, inDegree.get(neighbor)! - 1);
      if (inDegree.get(neighbor) === 0) {
        queue.push(neighbor);
      }
    }
  }

  if (result.length !== adjacency.size) {
    return '';
  }

  return result.join('');
}

