function minWindow(s: string, t: string): string {
  // 1. build a frequency map of required characters from t
  // 2. expand a right pointer over s, decrementing the needed count for
  //    each character seen; track how many DISTINCT required characters
  //    currently have their count fully satisfied
  // 3. once all required characters are satisfied, shrink from the left
  //    as much as possible while staying valid, recording the smallest
  //    valid window seen so far
  // 4. continue expanding right after shrinking
}

