class LFUCache {
  constructor(capacity: number) {
    // key ideas:
    // - keyToNode: key -> { value, freq }
    // - freqToList: frequency -> a doubly-linked list (or ordered structure)
    //   of keys currently at that frequency, ordered by recency within
    //   the frequency (front = most recently used at that freq)
    // - minFreq: track the current minimum frequency present in the cache,
    //   so eviction doesn't require scanning all frequencies
  }

  get(key: number): number {
    // if not present, return -1
    // otherwise: bump the key's frequency (move it from freqToList[oldFreq]
    // to freqToList[oldFreq + 1]), update minFreq if the old freq's list
    // is now empty and it was the minimum, return the value
  }

  put(key: number, value: number): void {
    // if capacity is 0, do nothing
    // if key exists, update value and bump frequency (same as get's bump logic)
    // if key is new and at capacity, evict from freqToList[minFreq] (the
    // least recently used entry at the lowest frequency)
    // insert the new key at frequency 1, reset minFreq to 1
  }
}

