class DLLNode {
  key: number;
  value: number;
  freq: number = 1;
  prev: DLLNode | null = null;
  next: DLLNode | null = null;

  constructor(key: number, value: number) {
    this.key = key;
    this.value = value;
  }
}

class FreqList {
  head: DLLNode;
  tail: DLLNode;
  size: number = 0;

  constructor() {
    this.head = new DLLNode(-1, -1);
    this.tail = new DLLNode(-1, -1);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  addFront(node: DLLNode): void {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next!.prev = node;
    this.head.next = node;
    this.size++;
  }

  remove(node: DLLNode): void {
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    this.size--;
  }

  removeLRU(): DLLNode {
    const lru = this.tail.prev!;
    this.remove(lru);
    return lru;
  }
}

class LFUCache {
  private capacity: number;
  private keyToNode: Map<number, DLLNode> = new Map();
  private freqToList: Map<number, FreqList> = new Map();
  private minFreq: number = 0;

  constructor(capacity: number) {
    this.capacity = capacity;
  }

  private getFreqList(freq: number): FreqList {
    if (!this.freqToList.has(freq)) {
      this.freqToList.set(freq, new FreqList());
    }
    return this.freqToList.get(freq)!;
  }

  private bumpFrequency(node: DLLNode): void {
    const oldFreq = node.freq;
    const oldList = this.freqToList.get(oldFreq)!;
    oldList.remove(node);

    if (oldList.size === 0 && this.minFreq === oldFreq) {
      this.minFreq++;
    }

    node.freq++;
    this.getFreqList(node.freq).addFront(node);
  }

  get(key: number): number {
    const node = this.keyToNode.get(key);
    if (!node) return -1;
    this.bumpFrequency(node);
    return node.value;
  }

  put(key: number, value: number): void {
    if (this.capacity === 0) return;

    const existing = this.keyToNode.get(key);
    if (existing) {
      existing.value = value;
      this.bumpFrequency(existing);
      return;
    }

    if (this.keyToNode.size >= this.capacity) {
      const list = this.freqToList.get(this.minFreq)!;
      const evicted = list.removeLRU();
      this.keyToNode.delete(evicted.key);
    }

    const node = new DLLNode(key, value);
    this.keyToNode.set(key, node);
    this.getFreqList(1).addFront(node);
    this.minFreq = 1;
  }
}
